--
-- Name: v_task_runs; Type: VIEW; Schema: public; Owner: admin
--

CREATE VIEW public.v_task_runs AS
 SELECT id,
    run_type,
    entity_type,
    entity_id,
        CASE
            WHEN ((entity_type)::text = 'database'::text) THEN ('database_'::text || entity_id)
            WHEN ((entity_type)::text = 'card'::text) THEN ('card_'::text || entity_id)
            WHEN ((entity_type)::text = 'dashboard'::text) THEN ('dashboard_'::text || entity_id)
            ELSE (((entity_type)::text || '_'::text) || entity_id)
        END AS entity_qualified_id,
    started_at,
    ended_at,
        CASE
            WHEN (ended_at IS NOT NULL) THEN (EXTRACT(epoch FROM (ended_at - started_at)))::double precision
            ELSE NULL::double precision
        END AS duration_seconds,
    status,
    process_uuid,
    updated_at
   FROM public.task_run;


ALTER VIEW public.v_task_runs OWNER TO admin;

